#!/usr/bin/perl
use strict;
use warnings;
use CGI;
use DBI;

my $cgi = CGI->new();
my $username = $cgi->param('username');
my $password = $cgi->param('password');

my $dsn = "DBI:mysql:database=mydb;host=localhost";
my $dbh = DBI->connect($dsn, 'user', 'pass') or die "Cannot connect to database: $DBI::errstr";

my $sth = $dbh->prepare("SELECT * FROM users WHERE username=? AND password=?");
$sth->execute($username, $password);

if ($sth->rows > 0) {
